# config.py
# Canonical reference data for synthetic ETL pipeline.
# Structure is designed for direct consumption by noise.py and pipeline.py.
# All lookup tables are dicts (O(1)) rather than lists — important at millions of rows.
# This file was generated by Claude AI and lightly reviewed by Sam Rodgers.
# The intention of this aspect of data generation is that it is somewhat of
#     a mystery to the developer who has to deal with normalizing potentially
#     unfamiliar data.

import uuid as _uuid

# ============================================================
# SHARED UUID HELPERS
# ============================================================

# Fixed namespaces — do not change after first run or all derived UUIDs will rotate.
_COMPANY_NS  = _uuid.UUID("a1b2c3d4-e5f6-7890-abcd-ef1234567890")
_INDUSTRY_NS = _uuid.UUID("b2c3d4e5-f6a7-8901-bcde-f12345678901")
_CATEGORY_NS = _uuid.UUID("c3d4e5f6-a7b8-9012-cdef-123456789012")

def _company_uuid(key: str) -> str:
    """Deterministic UUID from company short key. Stable across runs."""
    return str(_uuid.uuid5(_COMPANY_NS, key))

def _industry_uuid(name: str) -> str:
    """Deterministic UUID from industry name. Stable across runs."""
    return str(_uuid.uuid5(_INDUSTRY_NS, name))

def _category_uuid(name: str) -> str:
    """Deterministic UUID from category name. Stable across runs."""
    return str(_uuid.uuid5(_CATEGORY_NS, name))


