# ── Flat caches derived from COMPANIES ───────────────────────────────────────
# These are the structures consumed by transactions.py and noise.py.
# They are rebuilt by _rebuild_company_caches() whenever a company is added
# at runtime via register_company(). Do not modify them directly.

def _rebuild_company_caches():
    """
    Recompute all flat COMPANIES-derived caches in place.
    Called once at module load and again after every register_company() call.
    Mutates module-level names so all importers see the updated state without
    needing to re-import.
    """
    global COMPANY_KEYS, COMPANY_WEIGHTS, COMPANY_IDS, COMPANY_NAME_TO_UUID

    COMPANY_KEYS = list(COMPANIES.keys())

    # Weights must be normalised so they sum to 1.0 for np.random.choice.
    raw_weights = [COMPANIES[k]["weight"] for k in COMPANY_KEYS]
    total = sum(raw_weights)
    COMPANY_WEIGHTS = [w / total for w in raw_weights]

    COMPANY_IDS = [COMPANIES[k]["c_uuid"] for k in COMPANY_KEYS]

    # Reverse lookup: normalised name → c_uuid
    # Used by normalize_receipts() to recover c_id from injected name noise.
    COMPANY_NAME_TO_UUID = {v["name"].upper(): v["c_uuid"] for v in COMPANIES.values()}
    COMPANY_NAME_TO_UUID.update({
        "ORION SYSTEMS INC":  COMPANIES["COMP001"]["c_uuid"],
        "BLUEPEAK":           COMPANIES["COMP002"]["c_uuid"],
        "NEXADATA":           COMPANIES["COMP003"]["c_uuid"],
        "ALPENMART":          COMPANIES["COMP004"]["c_uuid"],
        "ZENPAY":             COMPANIES["COMP007"]["c_uuid"],
    })


# Initialise caches at import time.
COMPANY_KEYS: list[str]
COMPANY_WEIGHTS: list[float]
COMPANY_IDS: list[str]
COMPANY_NAME_TO_UUID: dict[str, str]
_rebuild_company_caches()


# ── Runtime company registration ──────────────────────────────────────────────

def register_company(
    key: str,
    name: str,
    industry_name: str,
    hq_country: str,
    region: str,
    default_cncy: str,
    weight: float = 0.05,
    c_uuid: str | None = None,
) -> dict:
    """
    Add a new company to the live registry at runtime.

    Intended for the dashboard's "ingest new company" flow — a company added
    here will immediately be visible to generate_transactions() and
    seed_companies() without restarting the process.

    The company is also written to analytics.d_company by the next
    run_seed() / seed_companies() call in transform.py. Callers that need
    the row in the DB immediately should call seed_companies() on an open
    connection after this.

    Args:
        key:           Short key, e.g. "COMP013". Must be unique in COMPANIES.
        name:          Human-readable company name.
        industry_name: Must be a key in INDUSTRIES (e.g. "Technology").
        hq_country:    Country string, e.g. "United States".
        region:        Region tag, e.g. "US_TECH".
        default_cncy:  ISO currency code for this company's default currency.
        weight:        Sampling weight for transaction generation. Will be
                       normalised against the full set automatically.
        c_uuid:        Optional explicit UUID. If omitted, derived from key
                       using the standard deterministic namespace — meaning the
                       same key always produces the same UUID.

    Returns:
        The newly created company dict (same shape as COMPANIES entries).

    Raises:
        ValueError: if key already exists, industry_name is unknown, or
                    default_cncy is not a recognised currency code.
    """
    if key in COMPANIES:
        raise ValueError(f"Company key {key!r} already exists in COMPANIES.")

    if industry_name not in INDUSTRIES:
        raise ValueError(
            f"Unknown industry {industry_name!r}. "
            f"Known industries: {list(INDUSTRIES.keys())}"
        )

    if default_cncy not in CURRENCY_CODES:
        raise ValueError(
            f"Unknown currency {default_cncy!r}. "
            f"Known codes: {sorted(CURRENCY_CODES)}"
        )

    entry = {
        "c_uuid":       c_uuid if c_uuid is not None else _company_uuid(key),
        "name":         name,
        "industry_id":  INDUSTRY_NAME_TO_ID[industry_name],
        "hq_country":   hq_country,
        "region":       region,
        "default_cncy": default_cncy,
        "weight":       weight,
    }

    COMPANIES[key] = entry
    _rebuild_company_caches()
    return entry


