def register_company_column_schema(key: str, schema: dict) -> None:
    """
    Register a custom column name schema for a company.

    Called after register_company() when the new company's data feed uses
    non-canonical column names. Updates CANONICAL_COLUMN_MAP in place so
    normalize_receipts() can resolve the new names immediately.

    Args:
        key:    Company key, e.g. "COMP013". Does not need to exist in
                COMPANIES — schemas can be registered independently.
        schema: Dict mapping canonical name → dirty name, e.g.
                {"tx_timestamp": "date", "amount": "gross_value", ...}
                Must use the same canonical keys as the "_default" schema.
    """
    COMPANY_COLUMN_SCHEMAS[key] = schema
    # Rebuild the inverted map so new dirty names are immediately resolvable.
    _rebuild_canonical_column_map()


def _rebuild_canonical_column_map() -> None:
    """Rebuild CANONICAL_COLUMN_MAP from the current COMPANY_COLUMN_SCHEMAS."""
    global CANONICAL_COLUMN_MAP
    CANONICAL_COLUMN_MAP = {}
    for _schema in COMPANY_COLUMN_SCHEMAS.values():
        for canonical, dirty in _schema.items():
            CANONICAL_COLUMN_MAP[dirty] = canonical


# Inverted: all known dirty column names → canonical name
# Auto-built from COMPANY_COLUMN_SCHEMAS so there's one place to update.
# Also rebuilt by _rebuild_canonical_column_map() when new schemas are added.
CANONICAL_COLUMN_MAP: dict[str, str]
_rebuild_canonical_column_map()


